@pytest.fixture def session(engine): connection = engine.connect() transaction = connection.begin() Session = sessionmaker(bind=connection) db = Session()
yield db
db.close() transaction.rollback() connection.close()

import uuid

@pytest.fixture
def unique_email():
    return f"test-{uuid.uuid4()}@example.com"

def test_user_registration(client, unique_email):
    response = client.post("/api/users", json={"email": unique_email})
    assert response.status_code == 201
